select count(*) from postgres.comments as c, postgres.posts as p, postgres.postlinks as pl, postgres.posthistory as ph, postgres.votes as v, postgres.badges as b where p.id = c.postid and p.id = pl.relatedpostid and p.id = ph.postid and p.id = v.postid and b.userid = c.userid and c.creationdate>=timestamp '2010-07-26 20:21:15' and c.creationdate<=timestamp '2014-09-13 18:12:10' and p.score<=61 and p.viewcount<=3627 and p.answercount>=0 and p.answercount<=5 and p.commentcount<=8 and p.favoritecount>=0 and v.votetypeid=2 and v.creationdate>=timestamp '2010-07-27 00:00:00' and b."date">=timestamp '2010-07-30 03:49:24';
